--- /dev/null
+++ b/modules/apps/frontend-editor/frontend-editor-ckeditor-web/scripts/remove-ckeditor-samples.js
@@ -0,0 +1,25 @@
+#!/usr/bin/env node
+
+/**
+ * Removes CKEditor samples directory to prevent XSS vulnerability
+ * CVE-2025-43761: Reflected XSS in ckeditor/samples/old/ajax.html
+ */
+
+const fs = require('fs');
+const path = require('path');
+
+const samplesPath = path.join(__dirname, '..', 'web', 'META-INF', 'resources', 'ckeditor', 'samples');
+
+if (fs.existsSync(samplesPath)) {
+  console.log('Removing CKEditor samples directory to prevent XSS vulnerability...');
+  fs.rmSync(samplesPath, { recursive: true, force: true });
+  console.log('CKEditor samples removed successfully.');
+} else {
+  console.log('CKEditor samples directory not found, skipping removal.');
+}
